func uniqRandn(n int) []int {
res, resMap := make([]int, 0, n),
make(map[int]struct{}, n)
for len(res) < n {
val := rand.Int()
if _, ok := resMap[val]; ok {
continue
}
res = append(res, val)
resMap[val] = struct{}{}
}
return res
}

func isMonotonic(in []int) bool {
isUp, isDown := true, true
for i := 1; i < len(in); i++ {
isDown = isDown && in[i-1] >= in[i]
isUp = isUp && in[i-1] <= in[i]
}
return isUp || isDown
}

